section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/pair-with-ai-agent-protocol.json",
  "type": "object",
  "title": "Pair with AI Agent Protocol",
  "required": [
    "session_id",
    "intent",
    "acceptance_tests",
    "models_used",
    "halt_events",
    "transcript_link"
  ],
  "additionalProperties": false,
  "properties": {
    "session_id": {
      "type": "string",
      "minLength": 1,
      "description": "Unique session identifier."
    },
    "intent": {
      "type": "string",
      "minLength": 1,
      "description": "One-sentence intent."
    },
    "acceptance_tests": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "Test names or paths the agent must make pass."
    },
    "models_used": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "Models invoked, e.g. ['opus', 'sonnet']."
    },
    "halt_events": {
      "type": "array",
      "items": {
        "type": "object"
      },
      "description": "List of halts; each {at, reason, decision}."
    },
    "transcript_link": {
      "type": "string",
      "minLength": 1,
      "description": "URL or path to the session log."
    },
    "commit_sha": {
      "type": [
        "string",
        "null"
      ],
      "description": "Final commit SHA if the session shipped."
    }
  }
}

example.code:
{
  "session_id": "2026-05-23-claude-001",
  "intent": "Add idempotency key to /payments/refund endpoint.",
  "acceptance_tests": [
    "tests/payments/test_refund.py::test_idempotent_refund"
  ],
  "models_used": [
    "opus",
    "sonnet"
  ],
  "halt_events": [
    {
      "at": "before_migration",
      "reason": "alembic upgrade head",
      "decision": "ratified"
    }
  ],
  "transcript_link": "logs/agent/2026-05-23-claude-001.md",
  "commit_sha": "abc123de"
}
